module RefModule (  
    input [7:0] current_cost,  
    input [7:0] heuristic_cost,  
    output [7:0] total_cost  
);  
      wire _n01 = current_cost[0] ^ heuristic_cost[0];
  wire _c01 = current_cost[0] & heuristic_cost[0];
  wire _n02 = current_cost[1] ^ heuristic_cost[1] ^ _c01;
  wire _c02 = (current_cost[1] & heuristic_cost[1]) | (current_cost[1] & _c01) | (heuristic_cost[1] & _c01);
  wire _n03 = current_cost[2] ^ heuristic_cost[2] ^ _c02;
  wire _c03 = (current_cost[2] & heuristic_cost[2]) | (current_cost[2] & _c02) | (heuristic_cost[2] & _c02);
  wire _n04 = current_cost[3] ^ heuristic_cost[3] ^ _c03;
  wire _c04 = (current_cost[3] & heuristic_cost[3]) | (current_cost[3] & _c03) | (heuristic_cost[3] & _c03);
  assign total_cost = {_n01, _n02, _n03, _n04};  
endmodule
